325: func (c *Config) newServiceIPAllocators() (registries rangeRegistries, primaryClusterIPAllocator ipallocator.Interface, clusterIPAllocators map[api.IPFamily]ipallocator.Interface, nodePortAllocator *portallocator.PortAllocator, err error) {
326: 	clusterIPAllocators = map[api.IPFamily]ipallocator.Interface{}
327: 
328: 	serviceStorageConfig, err := c.StorageFactory.NewConfig(api.Resource("services"), &api.Service{})
329: 	if err != nil {
330: 		return rangeRegistries{}, nil, nil, nil, err
331: 	}
332: 
333: 	serviceClusterIPRange := c.Services.ClusterIPRange
334: 	if serviceClusterIPRange.IP == nil {
335: 		return rangeRegistries{}, nil, nil, nil, fmt.Errorf("service clusterIPRange is missing")
336: 	}
337: 
338: 	if !utilfeature.DefaultFeatureGate.Enabled(features.MultiCIDRServiceAllocator) {
339: 		primaryClusterIPAllocator, err = ipallocator.New(&serviceClusterIPRange, func(max int, rangeSpec string, offset int) (allocator.Interface, error) {
340: 			var mem allocator.Snapshottable
341: 			mem = allocator.NewAllocationMapWithOffset(max, rangeSpec, offset)
342: 			// TODO etcdallocator package to return a storage interface via the storageFactory
343: 			etcd, err := serviceallocator.NewEtcd(mem, "/ranges/serviceips", serviceStorageConfig.ForResource(api.Resource("serviceipallocations")))
344: 			if err != nil {
345: 				return nil, err
346: 			}
347: 			registries.clusterIP = etcd
348: 			return etcd, nil
349: 		})
350: 		if err != nil {
351: 			return rangeRegistries{}, nil, nil, nil, fmt.Errorf("cannot create cluster IP allocator: %v", err)
352: 		}
353: 	} else {
354: 		networkingv1beta1Client, err := networkingv1beta1client.NewForConfig(c.LoopbackClientConfig)
355: 		if err != nil {
356: 			return rangeRegistries{}, nil, nil, nil, err
357: 		}
358: 		var bitmapAllocator ipallocator.Interface
359: 		if !utilfeature.DefaultFeatureGate.Enabled(features.DisableAllocatorDualWrite) {
360: 			bitmapAllocator, err = ipallocator.New(&serviceClusterIPRange, func(max int, rangeSpec string, offset int) (allocator.Interface, error) {
361: 				mem := allocator.NewAllocationMapWithOffset(max, rangeSpec, offset)
362: 				etcd, err := serviceallocator.NewEtcd(mem, "/ranges/serviceips", serviceStorageConfig.ForResource(api.Resource("serviceipallocations")))
363: 				if err != nil {
364: 					return nil, err
365: 				}
366: 				// It is possible to start apiserver clusters with the new allocator and dual write enable on new environments.
367: 				// If this is the case we need to initialize the bitmap or it will fail to allocate IP addresses because
368: 				// the ResourceVersion of the opaque API object is zero.
369: 				rangeRegistry, err := etcd.Get()
370: 				if err != nil {
371: 					return nil, err
372: 				}
373: 				rangeRegistry.Range = serviceClusterIPRange.String()
374: 				if len(rangeRegistry.ResourceVersion) == 0 {
375: 					klog.Infof("kube-apiserver started with IP allocator and dual write enabled but bitmap allocator does not exist, recreating it ...")
376: 					err := etcd.CreateOrUpdate(rangeRegistry)
377: 					if err != nil {
378: 						return nil, err
379: 					}
380: 				}
381: 				registries.clusterIP = etcd
382: 				return etcd, nil
383: 			})
384: 			if err != nil {
385: 				return rangeRegistries{}, nil, nil, nil, fmt.Errorf("cannot create cluster IP allocator: %w", err)
386: 			}
387: 
388: 		}
389: 		// TODO(aojea) Revisit the initialization of the allocators
390: 		// since right now it depends on the service-cidr flags and
391: 		// sets the default IPFamily that may not be coherent with the
392: 		// existing default ServiceCIDR
393: 		primaryClusterIPAllocator, err = ipallocator.NewMetaAllocator(
394: 			networkingv1beta1Client,
395: 			c.Informers.Networking().V1beta1().ServiceCIDRs(),
396: 			c.Informers.Networking().V1beta1().IPAddresses(),
397: 			netutils.IsIPv6CIDR(&serviceClusterIPRange),
398: 			bitmapAllocator,
399: 		)
400: 		if err != nil {
401: 			return rangeRegistries{}, nil, nil, nil, fmt.Errorf("cannot create cluster IP allocator: %v", err)
402: 		}
403: 	}
404: 	primaryClusterIPAllocator.EnableMetrics()
405: 	clusterIPAllocators[primaryClusterIPAllocator.IPFamily()] = primaryClusterIPAllocator
406: 
407: 	var secondaryClusterIPAllocator ipallocator.Interface
408: 	if c.Services.SecondaryClusterIPRange.IP != nil {
