411: 			secondaryClusterIPAllocator, err = ipallocator.New(&c.Services.SecondaryClusterIPRange, func(max int, rangeSpec string, offset int) (allocator.Interface, error) {
412: 				var mem allocator.Snapshottable
413: 				mem = allocator.NewAllocationMapWithOffset(max, rangeSpec, offset)
414: 				// TODO etcdallocator package to return a storage interface via the storageFactory
415: 				etcd, err := serviceallocator.NewEtcd(mem, "/ranges/secondaryserviceips", serviceStorageConfig.ForResource(api.Resource("serviceipallocations")))
416: 				if err != nil {
417: 					return nil, err
418: 				}
419: 				registries.secondaryClusterIP = etcd
420: 				return etcd, nil
421: 			})
422: 			if err != nil {
423: 				return rangeRegistries{}, nil, nil, nil, fmt.Errorf("cannot create cluster secondary IP allocator: %v", err)
424: 			}
425: 		} else {
426: 			networkingv1beta1Client, err := networkingv1beta1client.NewForConfig(c.LoopbackClientConfig)
427: 			if err != nil {
428: 				return rangeRegistries{}, nil, nil, nil, err
429: 			}
430: 			var bitmapAllocator ipallocator.Interface
431: 			if !utilfeature.DefaultFeatureGate.Enabled(features.DisableAllocatorDualWrite) {
432: 				bitmapAllocator, err = ipallocator.New(&c.Services.SecondaryClusterIPRange, func(max int, rangeSpec string, offset int) (allocator.Interface, error) {
433: 					mem := allocator.NewAllocationMapWithOffset(max, rangeSpec, offset)
434: 					// TODO etcdallocator package to return a storage interface via the storageFactory
435: 					etcd, err := serviceallocator.NewEtcd(mem, "/ranges/secondaryserviceips", serviceStorageConfig.ForResource(api.Resource("serviceipallocations")))
436: 					if err != nil {
437: 						return nil, err
438: 					}
439: 					// It is possible to start apiserver clusters with the new allocator and dual write enable on new environments.
440: 					// If this is the case we need to initialize the bitmap or it will fail to allocate IP addresses because
441: 					// the ResourceVersion of the opaque API object is zero.
442: 					rangeRegistry, err := etcd.Get()
443: 					if err != nil {
444: 						return nil, err
445: 					}
446: 					rangeRegistry.Range = c.Services.SecondaryClusterIPRange.String()
447: 					if len(rangeRegistry.ResourceVersion) == 0 {
448: 						klog.Infof("kube-apiserver started with IP allocator and dual write enabled but bitmap allocator does not exist, recreating it ...")
449: 						err := etcd.CreateOrUpdate(rangeRegistry)
450: 						if err != nil {
451: 							return nil, err
452: 						}
453: 					}
454: 					registries.secondaryClusterIP = etcd
455: 					return etcd, nil
456: 				})
457: 				if err != nil {
458: 					return rangeRegistries{}, nil, nil, nil, fmt.Errorf("cannot create cluster secondary IP allocator: %w", err)
459: 				}
460: 			}
461: 			// TODO(aojea) Revisit the initialization of the allocators
462: 			// since right now it depends on the service-cidr flags and
463: 			// sets the default IPFamily that may not be coherent with the
464: 			// existing default ServiceCIDR
465: 			secondaryClusterIPAllocator, err = ipallocator.NewMetaAllocator(
466: 				networkingv1beta1Client,
467: 				c.Informers.Networking().V1beta1().ServiceCIDRs(),
468: 				c.Informers.Networking().V1beta1().IPAddresses(),
