474: 			}
475: 		}
476: 		secondaryClusterIPAllocator.EnableMetrics()
477: 		clusterIPAllocators[secondaryClusterIPAllocator.IPFamily()] = secondaryClusterIPAllocator
478: 	}
479: 
480: 	nodePortAllocator, err = portallocator.New(c.Services.NodePortRange, func(max int, rangeSpec string, offset int) (allocator.Interface, error) {
