500: func (p *legacyProvider) PostStartHook() (string, genericapiserver.PostStartHookFunc, error) {
501: 	return "start-service-ip-repair-controllers", func(context genericapiserver.PostStartHookContext) error {
502: 		// We start both repairClusterIPs and repairNodePorts to ensure repair
503: 		// loops of ClusterIPs and NodePorts.
504: 		// We run both repair loops using RunUntil public interface.
505: 		// However, we want to fail liveness/readiness until the first
506: 		// successful repair loop, so we basically pass appropriate
507: 		// callbacks to RunUtil methods.
508: 		// Additionally, we ensure that we don't wait for it for longer
509: 		// than 1 minute for backward compatibility of failing the whole
510: 		// apiserver if we can't repair them.
511: 		wg := sync.WaitGroup{}
512: 		wg.Add(2)
513: 		runner := async.NewRunner(
514: 			func(stopCh chan struct{}) { p.startServiceClusterIPRepair(wg.Done, stopCh) },
515: 			func(stopCh chan struct{}) { p.startServiceNodePortsRepair(wg.Done, stopCh) },
516: 		)
517: 		runner.Start()
518: 		go func() {
519: 			defer runner.Stop()
520: 			<-context.Done()
521: 		}()
522: 
523: 		// For backward compatibility, we ensure that if we never are able
524: 		// to repair clusterIPs and/or nodeports, we not only fail the liveness
525: 		// and/or readiness, but also explicitly fail.
526: 		done := make(chan struct{})
527: 		go func() {
528: 			defer close(done)
529: 			wg.Wait()
530: 		}()
531: 		select {
532: 		case <-done:
533: 		case <-time.After(time.Minute):
534: 			return goerrors.New("unable to perform initial IP and Port allocation check")
535: 		}
536: 
537: 		return nil
538: 	}, nil
539: }
