550: 	// this is fragile, which assumes that the default port is being used
551: 	// TODO: switch to secure port until these components remove the ability to serve insecurely.
552: 	serversToValidate := map[string]componentstatus.Server{
553: 		"controller-manager": &componentstatus.HttpServer{EnableHTTPS: true, TLSConfig: &tls.Config{InsecureSkipVerify: true}, Addr: "127.0.0.1", Port: ports.KubeControllerManagerPort, Path: "/healthz"},
