68: func (c *GenericConfig) NewRESTStorage(apiResourceConfigSource serverstorage.APIResourceConfigSource, restOptionsGetter generic.RESTOptionsGetter) (genericapiserver.APIGroupInfo, error) {
69: 	apiGroupInfo := genericapiserver.APIGroupInfo{
70: 		PrioritizedVersions:          legacyscheme.Scheme.PrioritizedVersionsForGroup(""),
71: 		VersionedResourcesStorageMap: map[string]map[string]rest.Storage{},
72: 		Scheme:                       legacyscheme.Scheme,
73: 		ParameterCodec:               legacyscheme.ParameterCodec,
74: 		NegotiatedSerializer:         legacyscheme.Codecs,
75: 	}
76: 	if utilfeature.DefaultFeatureGate.Enabled(features.CBORServingAndStorage) {
77: 		apiGroupInfo.NegotiatedSerializer = serializer.NewCodecFactory(legacyscheme.Scheme, serializer.WithSerializer(cbor.NewSerializerInfo))
78: 	}
79: 
80: 	eventStorage, err := eventstore.NewREST(restOptionsGetter, uint64(c.EventTTL.Seconds()))
81: 	if err != nil {
82: 		return genericapiserver.APIGroupInfo{}, err
83: 	}
84: 
85: 	resourceQuotaStorage, resourceQuotaStatusStorage, err := resourcequotastore.NewREST(restOptionsGetter)
86: 	if err != nil {
87: 		return genericapiserver.APIGroupInfo{}, err
88: 	}
89: 	secretStorage, err := secretstore.NewREST(restOptionsGetter)
90: 	if err != nil {
91: 		return genericapiserver.APIGroupInfo{}, err
92: 	}
93: 
94: 	configMapStorage, err := configmapstore.NewREST(restOptionsGetter)
95: 	if err != nil {
96: 		return genericapiserver.APIGroupInfo{}, err
97: 	}
98: 
99: 	namespaceStorage, namespaceStatusStorage, namespaceFinalizeStorage, err := namespacestore.NewREST(restOptionsGetter)
100: 	if err != nil {
101: 		return genericapiserver.APIGroupInfo{}, err
102: 	}
103: 
104: 	var serviceAccountStorage *serviceaccountstore.REST
105: 	if c.ServiceAccountIssuer != nil {
106: 		serviceAccountStorage, err = serviceaccountstore.NewREST(restOptionsGetter, c.ServiceAccountIssuer, c.APIAudiences, c.ServiceAccountMaxExpiration, newNotFoundGetter(schema.GroupResource{Resource: "pods"}), secretStorage.Store, newNotFoundGetter(schema.GroupResource{Resource: "nodes"}), c.ExtendExpiration, c.IsTokenSignerExternal)
107: 	} else {
108: 		serviceAccountStorage, err = serviceaccountstore.NewREST(restOptionsGetter, nil, nil, 0, newNotFoundGetter(schema.GroupResource{Resource: "pods"}), newNotFoundGetter(schema.GroupResource{Resource: "secrets"}), newNotFoundGetter(schema.GroupResource{Resource: "nodes"}), false, c.IsTokenSignerExternal)
109: 	}
110: 	if err != nil {
111: 		return genericapiserver.APIGroupInfo{}, err
112: 	}
113: 
114: 	storage := map[string]rest.Storage{}
115: 	if resource := "events"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
116: 		storage[resource] = eventStorage
117: 	}
118: 
119: 	if resource := "resourcequotas"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
120: 		storage[resource] = resourceQuotaStorage
121: 		storage[resource+"/status"] = resourceQuotaStatusStorage
122: 	}
123: 
124: 	if resource := "namespaces"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
125: 		storage[resource] = namespaceStorage
126: 		storage[resource+"/status"] = namespaceStatusStorage
127: 		storage[resource+"/finalize"] = namespaceFinalizeStorage
128: 	}
129: 
130: 	if resource := "secrets"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
131: 		storage[resource] = secretStorage
132: 	}
133: 
134: 	if resource := "serviceaccounts"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
135: 		storage[resource] = serviceAccountStorage
136: 		if serviceAccountStorage.Token != nil {
137: 			storage[resource+"/token"] = serviceAccountStorage.Token
138: 		}
139: 	}
140: 
141: 	if resource := "configmaps"; apiResourceConfigSource.ResourceEnabled(corev1.SchemeGroupVersion.WithResource(resource)) {
142: 		storage[resource] = configMapStorage
143: 	}
144: 
145: 	if len(storage) > 0 {
146: 		apiGroupInfo.VersionedResourcesStorageMap["v1"] = storage
147: 	}
148: 
149: 	return apiGroupInfo, nil
150: }
